import java.util.*;class A{static int W,H,turn;static boolean[][]wall;static List<int[]>nodes=new ArrayList<>(),bombs=new ArrayList<>();static int[][]prev;static int[]mv(int[]n){int x=n[0],y=n[1],dx=n[2],dy=n[3];if(dx==0&&dy==0)return new int[]{x,y,dx,dy};int nx=x+dx,ny=y+dy;if(nx<0||nx>=W||ny<0||ny>=H||wall[ny][nx]){dx=-dx;dy=-dy;nx=x+dx;ny=y+dy;}return new int[]{nx,ny,dx,dy};}static List<int[]>sim(List<int[]>ns,int t){var c=new ArrayList<int[]>();for(var n:ns)c.add(n.clone());for(int i=0;i<t;i++){var nc=new ArrayList<int[]>();for(var n:c)nc.add(mv(n));c=nc;}return c;}static Set<Integer>blast(int bx,int by){var r=new HashSet<Integer>();r.add(by*W+bx);int[]dx={0,0,1,-1},dy={1,-1,0,0};for(int d=0;d<4;d++)for(int i=1;i<=3;i++){int cx=bx+dx[d]*i,cy=by+dy[d]*i;if(cx<0||cx>=W||cy<0||cy>=H||wall[cy][cx])break;r.add(cy*W+cx);}return r;}public static void main(String[]args){var s=new Scanner(System.in);W=s.nextInt();H=s.nextInt();wall=new boolean[H][W];for(;;){int rl=s.nextInt(),ba=s.nextInt();s.nextLine();var cur=new ArrayList<int[]>();var grid=new String[H];for(int y=0;y<H;y++){grid[y]=s.nextLine();for(int x=0;x<W;x++){if(turn==0&&grid[y].charAt(x)=='#')wall[y][x]=true;if(grid[y].charAt(x)=='@')cur.add(new int[]{x,y});}}if(turn==0){nodes.clear();for(var c:cur)nodes.add(new int[]{c[0],c[1],0,0});prev=cur.toArray(new int[0][]);}else if(turn==1){var used=new HashSet<Integer>();var nn=new ArrayList<int[]>();for(var p:prev){int best=-1,bd=99;for(int i=0;i<cur.size();i++){if(used.contains(i))continue;int d=Math.abs(cur.get(i)[0]-p[0])+Math.abs(cur.get(i)[1]-p[1]);if(d<bd){bd=d;best=i;}}if(best>=0&&bd<=1){used.add(best);nn.add(new int[]{cur.get(best)[0],cur.get(best)[1],cur.get(best)[0]-p[0],cur.get(best)[1]-p[1]});}}for(int i=0;i<cur.size();i++)if(!used.contains(i))nn.add(new int[]{cur.get(i)[0],cur.get(i)[1],0,0});nodes=nn;}else{var um=new HashMap<Integer,int[]>();for(var c:cur)um.put(c[1]*W+c[0],c);var nn=new ArrayList<int[]>();for(var n:nodes){var m=mv(n);int k=m[1]*W+m[0];if(um.containsKey(k)){nn.add(m);um.remove(k);}}for(var v:um.values())nn.add(new int[]{v[0],v[1],0,0});nodes=nn;}for(var b:bombs)b[2]--;boolean ch=true;while(ch){ch=false;for(int i=bombs.size()-1;i>=0;i--)if(bombs.get(i)[2]<=0){var cells=blast(bombs.get(i)[0],bombs.get(i)[1]);bombs.remove(i);nodes.removeIf(n->cells.contains(n[1]*W+n[0]));for(var b:bombs)if(cells.contains(b[1]*W+b[0]))b[2]=0;ch=true;}}if(ba==0||nodes.isEmpty()||turn==0){System.out.println("WAIT");System.out.flush();prev=cur.toArray(new int[0][]);turn++;continue;}int mw=Math.min(rl-4,55),bw=-1,bx=-1,by=-1,bh=0;for(int w=0;w<=mw;w++){var ab=sim(nodes,w+3);var ap=w>0?sim(nodes,w):null;var cs=new HashMap<Integer,Integer>();for(var n:ab)for(int c:blast(n[0],n[1]))cs.merge(c,1,Integer::sum);var ps=new HashSet<Integer>();if(ap!=null)for(var n:ap)ps.add(n[1]*W+n[0]);for(var e:cs.entrySet()){if(e.getValue()<=bh)continue;int x=e.getKey()%W,y=e.getKey()/W;if(wall[y][x])continue;if(w==0&&grid[y].charAt(x)!='.')continue;if(w>0&&ps.contains(e.getKey()))continue;boolean dup=false;for(var b:bombs)if(b[0]==x&&b[1]==y)dup=true;if(dup)continue;bh=e.getValue();bw=w;bx=x;by=y;}if(bh>=nodes.size())break;}if(bw==0&&bh>0){bombs.add(new int[]{bx,by,3});System.out.println(bx+" "+by);}else System.out.println("WAIT");System.out.flush();turn++;}}}